UPDATE content_schedule
SET current_ticket = current_ticket - #{total_qty}
WHERE schedule_id = #{schedule_id} 
	AND current_ticket >= #{total_qty}

UPDATE content_schedule
SET current_ticket = LEAST(current_ticket + #{total_qty}, total_ticket)
WHERE schedule_id = #{schedule_id}

UPDATE payment
SET payment_status = #{payment_status}
WHERE order_key = #{order_key}
